#include <stdio.h>

int main() {
    int niz[] = { 1, 0, 3, -5, 4 };
    int *p = &niz[1];

    /* Uvećavanje vrijednosti drugog člana niza za 1 */
    (*p)++;
    printf("Drugi clan: %d\n", *p);
    
    /* Postavljanje nove vrijednosti pretposljednjeg člana niza */
    *(p+2) *= 2;
    printf("Nova vrijednost pretposljednjeg elementa: %d\n", *(p + 2));

    return 0;
}
